public class StudyLog {
  public static void main(String[] args) {
    // 学習ログの出力
    String topic = "Java 出力";
    int minutes = 45;
    boolean done = false;

    System.out.println("=== Study Log ===");
    System.out.println("Topic:\t" + topic);
    System.out.println("Minutes:\t" + minutes);

    if (!done) {
      System.out.println("まだ途中。でも大丈夫、続きは次回やろう。");
    }
  }
}
